// 定义需要校验的字段及其预期类型
// 对应你的 C# LeakageTestSystem 类
const requiredFields = [
  { name: 'SN', type: 'string' },
  { name: 'isOK', type: 'boolean' },
  { name: 'status', type: 'number' },                      // ushort -> number
  { name: 'intakeDuration', type: 'number' },               // double -> number
  { name: 'pressureStabilizationDuration', type: 'number' },// double -> number
  { name: 'testDuration', type: 'number' },                 // double -> number
  { name: 'deflationDuration', type: 'number' },            // double -> number
  { name: 'intakePressure', type: 'number' },               // int -> number
  { name: 'leakageUpperLimit', type: 'number' },            // int -> number
  { name: 'leakageLowerLimit', type: 'number' },            // int -> number
  { name: 'testSmallLeakValue', type: 'number' },           // int -> number
  { name: 'testLargeLeakValue', type: 'number' },           // int -> number
  { name: 'leakValue', type: 'number' }                     // int -> number
];

// 遍历每一个输入项 (item)
for (const item of items) {
  const data = item.json;
  const missingFields = [];

  for (const field of requiredFields) {
    const value = data[field.name];

    // 校验逻辑
    let isValid = true;

    if (value === undefined || value === null) {
      isValid = false;
    } else {
      switch (field.type) {
        case 'string':
          // 字符串不能为空且不能只包含空格
          if (typeof value !== 'string' || value.trim() === '') {
            isValid = false;
          }
          break;

        case 'number':
          // 数字必须是有效的数字类型（排除 NaN），但在工业数据中 0 是有效值，所以不检查 !value
          if (typeof value !== 'number' || isNaN(value)) {
            isValid = false;
          }
          break;

        case 'boolean':
          // 布尔值必须是 true 或 false
          if (typeof value !== 'boolean') {
            isValid = false;
          }
          break;
      }
    }

    if (!isValid) {
      missingFields.push(field.name);
    }
  }

  // 将校验结果附加到输出数据中
  if (missingFields.length > 0) {
    // 方案 A: 标记该数据为错误 (推荐)
    item.json.validationPassed = false;
    item.json.errorMsg = `缺少参数或参数格式错误: ${missingFields.join(', ')}`;
  } else {
    // 方案 B: 校验通过
    item.json.validationPassed = true;
  }
}

// 返回处理后的数据
// 如果你想过滤掉错误的数据，可以在此之后接一个 "If" 节点判断 validationPassed 为 true
return items;
